cd /tmp && cat > TestStackalloc.cs << 'EOF'
using System;

class Program
{
    static void Main()
    {
        Span<nint> a = stackalloc nint[4];
        a[0] = 42;
        a[1] = nint.MaxValue;
        Console.WriteLine($"nint span: [{a[0]}, {a[1]}, {a[2]}, {a[3]}]");

        Span<nuint> b = stackalloc nuint[3];
        b[0] = 99;
        b[1] = nuint.MaxValue;
        Console.WriteLine($"nuint span: [{b[0]}, {b[1]}, {b[2]}]");
        Console.WriteLine($"sizeof(nint) = {sizeof(nint)}");
    }
}
EOF
